import axios from "axios";
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

export const Navigationhome = (props) => {
  const [isCollapsed, setIsCollapsed] = useState(true);
  const Nav = useNavigate();
  const [data, setData] = useState({
    profile: "",
    fname: "",
    lname: "",
  });

  useEffect(() => {
    axios
      .get(
        `https://space-club.onrender.com/getdata/${window.localStorage.getItem(
          "user"
        )}`
      )
      .then((res) => {
        setData({
          profile: res.data.profile,
          fname: res.data.fname,
          lname: res.data.lname,
        });
      })
      .catch((error) => {
        console.error("Error fetching data:", error);
      });
  }, []);

  const toggleNavbarCollapse = () => {
    setIsCollapsed(!isCollapsed);
  };

  const Getlogout = () => {
    Nav("/logout");
    toggleNavbarCollapse();
  };

  const Gotosettings = () => {
    Nav("/editprofile");
    toggleNavbarCollapse();
  };

  const Gotohome = () => {
    Nav("/home");
    toggleNavbarCollapse();
  };

  const Gotoprojects = () => {
    Nav("/projects");
    toggleNavbarCollapse();
  };

  return (
    <nav
      id="menu"
      className="navbar navbar-default navbar-fixed-top"
      style={{ display: "flex", justifyContent: "space-between" }}
    >
      <div className="container">
        <a className="navbar-brand page-scroll" href="#page-top" id="navigationmain">
          <img src="https://space-club.onrender.com/img/nav_icon.jpg" alt="astec logo" />
          <h1>ASTEC</h1>
        </a>{" "}
        <div className="navbar-header">
          <button
            type="button"
            className="navbar-toggle collapsed"
            onClick={toggleNavbarCollapse}
            aria-expanded={!isCollapsed}
          >
            <span className="sr-only">Toggle navigation</span>{" "}
            <span className="icon-bar"></span>{" "}
            <span className="icon-bar"></span>{" "}
            <span className="icon-bar"></span>{" "}
          </button>
        </div>
        <div
          className={`collapse navbar-collapse ${
            isCollapsed ? "" : "in"
          }`}
          style={{
            width: isCollapsed ? "0" : "100%",
            transition: "width 0.3s",
            display: "flex",
            alignItems: "center",
          }}
        >
          <ul
            id="ulnav"
            className="nav navbar-nav navbar-right"
            style={{ display: "flex", flexDirection: "row" }}
          >
            <li>
              <a style={{ backgroundColor: "transparent" }} href="#features" className="page-scroll">
                Events
              </a>
            </li>
            {/* Add other menu items here */}
          </ul>
        </div>
      </div>
      <img src={`https://space-club.onrender.com/profile/${data.profile}`} id="profilesubimg" style={{ marginRight: "20px" }} />
      <h3 style={{ display: "none" }}>{data.fname} {data.lname}</h3>
      <div id="subnav" style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
        <a className="dropdown-item" id="profilea" href="#" onClick={() => { Gotohome() }}>HOME</a><br />
        <a className="dropdown-item" id="profilea" href="#" onClick={() => { Gotoprojects() }}>PROJECTS</a><br />
        <a className="dropdown-item" id="profilea" href="#" onClick={() => { Getlogout() }}>TEAMS</a><br />
        <a className="dropdown-item" id="profilea" href="#" onClick={() => { Gotosettings() }}>SETTINGS</a><br />
        <a className="dropdown-item" id="profilea" href="#" onClick={() => { Getlogout() }}>LOGOUT</a>
      </div>
    </nav>
  );
};
